class Solution {
public:
    long long maximumOr(vector<int>& nums, int k) {
        long long res = 0;
        for (int num : nums) res |= num;
        long long ans = res;
        for (int i = 0; i < nums.size(); i++) {
            long long cur = res;
            int cnt = 0;
            for (int j = 0; j < 31; j++) {
                if (!(cur & (1LL << j)) && (nums[i] & (1LL << j))) {
                    if (cnt >= k) break;
                    cur |= (1LL << j);
                    cnt++;
                }
            }
            ans = max(ans, cur);
        }
        return ans;
    }
};

